changeSet.sql:
-- BCVA Letters (ETDRS) UPDATE item_form_metadata ifm SET left_item_text = 'Rechtes Auge (OD) — BCVA Buchstaben', right_item_text = 'letters (0–100)' FROM item i WHERE ifm.item_id = i.item_id AND ifm.crf_version_id = 3 AND i.oc_oid = 'I_OPHTH_OD_BCVA_LETTERS';
UPDATE item_form_metadata ifm SET left_item_text = 'Linkes Auge (OS) — BCVA Buchstaben', right_item_text = 'letters (0–100)' FROM item i WHERE ifm.item_id = i.item_id AND ifm.crf_version_id = 3 AND i.oc_oid = 'I_OPHTH_OS_BCVA_LETTERS';
-- Augeninnendruck (IOP) UPDATE item_form_metadata ifm SET left_item_text = 'Rechtes Auge (OD) — Augeninnendruck', right_item_text = 'mmHg (10–21)' FROM item i WHERE ifm.item_id = i.item_id AND ifm.crf_version_id = 3 AND i.oc_oid = 'I_OPHTH_OD_IOP';
UPDATE item_form_metadata ifm SET left_item_text = 'Linkes Auge (OS) — Augeninnendruck', right_item_text = 'mmHg (10–21)' FROM item i WHERE ifm.item_id = i.item_id AND ifm.crf_version_id = 3 AND i.oc_oid = 'I_OPHTH_OS_IOP';
