UPDATE item_form_metadata ifm SET left_item_text = 'Linkes Auge (OS) — Spectralis-OCT durchgeführt', right_item_text = '' FROM item i WHERE ifm.item_id = i.item_id AND ifm.crf_version_id = 3 AND i.oc_oid = 'I_OPHTH_OS_SPECTRALIS_OCT_DONE';
-- Spectralis OCT — Grund falls nicht durchgeführt UPDATE item_form_metadata ifm SET left_item_text = 'Rechtes Auge (OD) — Spectralis-OCT Grund', right_item_text = '' FROM item i WHERE ifm.item_id = i.item_id AND ifm.crf_version_id = 3 AND i.oc_oid = 'I_OPHTH_OD_SPECTRALIS_OCT_REASON';
UPDATE item_form_metadata ifm SET left_item_text = 'Linkes Auge (OS) — Spectralis-OCT Grund', right_item_text = '' FROM item i WHERE ifm.item_id = i.item_id AND ifm.crf_version_id = 3 AND i.oc_oid = 'I_OPHTH_OS_SPECTRALIS_OCT_REASON';
-- Refraktion: Sphäre UPDATE item_form_metadata ifm SET left_item_text = 'Rechtes Auge (OD) — Sphäre', right_item_text = 'dpt' FROM item i WHERE ifm.item_id = i.item_id AND ifm.crf_version_id = 3 AND i.oc_oid = 'I_OPHTH_OD_REFRACTION_SPHERE';
UPDATE item_form_metadata ifm SET left_item_text = 'Linkes Auge (OS) — Sphäre', right_item_text = 'dpt' FROM item i WHERE ifm.item_id = i.item_id AND ifm.crf_version_id = 3 AND i.oc_oid = 'I_OPHTH_OS_REFRACTION_SPHERE';
-- Refraktion: Zylinder (Torus) UPDATE item_form_metadata ifm SET left_item_text = 'Rechtes Auge (OD) — Zylinder', right_item_text = 'dpt' FROM item i WHERE ifm.item_id = i.item_id AND ifm.crf_version_id = 3 AND i.oc_oid = 'I_OPHTH_OD_REFRACTION_TORUS';
UPDATE item_form_metadata ifm SET left_item_text = 'Linkes Auge (OS) — Zylinder', right_item_text = 'dpt' FROM item i WHERE ifm.item_id = i.item_id AND ifm.crf_version_id = 3 AND i.oc_oid = 'I_OPHTH_OS_REFRACTION_TORUS';
-- Refraktion: Achse (Angle) UPDATE item_form_metadata ifm SET left_item_text = 'Rechtes Auge (OD) — Achse', right_item_text = '°' FROM item i WHERE ifm.item_id = i.item_id AND ifm.crf_version_id = 3 AND i.oc_oid = 'I_OPHTH_OD_REFRACTION_ANGLE';
UPDATE item_form_metadata ifm SET left_item_text = 'Linkes Auge (OS) — Achse', right_item_text = '°' FROM item i WHERE ifm.item_id = i.item_id AND ifm.crf_version_id = 3 AND i.oc_oid = 'I_OPHTH_OS_REFRACTION_ANGLE';
